import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
      
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error("Erreur API:", err));
    }, []);

    return (
        <header className="bg-white border-bottom sticky-top">
            <div className="container py-3">
                <div className="row align-items-center">
                    <div className="col-8 col-md-4">
                        <Link to="/"><img src={logo} alt="Logo" style={{ width: '250px' }} /></Link>
                    </div>

                    <div className="col-12 col-md-8 text-end">
                        <div className="d-flex flex-column align-items-end">
                            <div className="position-relative mb-2" style={{ width: '200px' }}>
                                <input className="form-control border-0 border-bottom rounded-0 shadow-none ps-0" type="text" placeholder="Rechercher" style={{ borderBottom: '2px solid #004a99' }} />
                                <span className="position-absolute end-0 top-50 translate-middle-y">🔍</span>
                            </div>
                            
                            <ul className="nav justify-content-end fw-bold">
                                {categories.length > 0 ? categories.map((cat) => (
                                    <li className="nav-item" key={cat.id}>
                                        <Link className="nav-link text-dark px-2" to={`/category/${cat.id}`}>{cat.name}</Link>
                                    </li>
                                )) : <li className="nav-item small text-muted">Chargement...</li>}
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
